INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-07', '06:11:39', 46, 20, 3, 0, 0, 301, 69, 22.92, 'https://x.com/sandmark_news/status/2052270114264039836', '9/ Conclusion: Beyond the Blended Rate  DeFi’s compounding risk problem stems from interconnectedness. By moving past the blended rate and localizing risk via tranches, @LotusFi_ provides a lending architecture built for systemic stability and capital efficiency.  Read the full Analysis by @yasche_ ⬇️  https://www.sandmark.com/news/analysis/credit-tranching-unlocks-defi-lending-efficiency', NULL);
INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-07', '06:11:38', 44, 20, 3, 0, 0, 281, 67, 23.84, 'https://x.com/sandmark_news/status/2052270111973904655', '8/ Pricing Risk Explicitly  By decomposing borrow rates into a floor yield and a credit spread, @LotusFi_ prices risk explicitly. It gives participants control over their exposure, 80% LLTV senior lenders exit before 95% LLTV junior lenders, providing a real-time risk buffer.', NULL);
