INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-07', '06:11:36', 45, 23, 3, 0, 0, 283, 71, 25.09, 'https://x.com/sandmark_news/status/2052270102020808726', '5/ Cascading Liquidity Without Shared Risk  To prevent rate spikes, @LotusFi_ uses a "liquidity cascade." Idle supply from junior tranches flows down to fill demand at the senior end. While liquidity is shared, the risk remains localized: losses only impact the tranche that originally underwrote the exposure.', NULL);
