INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-06', '07:19:27', 42, 23, 3, 0, 0, 250, 68, 27.2, 'https://x.com/sandmark_news/status/2051924788508340394', '2/ VOLATILITY BECOMES A TRADABLE ASSET  The contracts settle to the CME CF Bitcoin Volatility Index (BVX), which tracks a 30-day forward-looking measure of implied volatility.  Unlike traditional futures, this allows participants to trade "market fear" independently.   If you expect a massive move but aren''t sure which way, you can now trade that expectation directly.', NULL);
INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-06', '07:19:27', 41, 17, 2, 0, 0, 294, 60, 20.41, 'https://x.com/sandmark_news/status/2051924790836097454', '3/ MARKET STRUCTURE DEEPENS  This launch signals a shift from simple directional "long or short" betting toward sophisticated institutional strategies.   By providing tools to hedge options exposure and express views on sentiment, CME is industrializing crypto risk management to look more like traditional finance.  Full Report ⬇️ https://www.sandmark.com/news/top-news/cme-debut-bitcoin-volatility-futures-amid-digital-products-expansion', NULL);
