INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-06', '06:43:22', 41, 16, 1, 0, 0, 202, 58, 28.71, 'https://x.com/sandmark_news/status/2051915707529453820', '6/ Flight to Quality: stETH Collateral Shifts  Post-exploit onchain data shows a "flight to quality."  While #stETH collateral fell in higher-risk venues like @aave, it surged in @sparkdotfi (386k ETH inflow) and @Morpho. Holders didn''t exit stETH; they rotated it to protocols with more insulated risk frameworks.', NULL);
INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-06', '06:43:22', 44, 16, 6, 1, 0, 495, 67, 13.54, 'https://x.com/sandmark_news/status/2051915710860066994', '7/ The Concentration Debate and the Path to Decentralization  Lido’s dominance at 22.3% of all staked ETH remains a liability for some. However, the protocol is addressing this via the Community Staking Module (CSM) and "Dual Governance," which gives stakers programmatic power to veto DAO decisions.  Check out our full analysis from @yasche_ ⬇️  https://www.sandmark.com/news/analysis/lockup-liquidity-lido-satisfies-hunger-yield-bearing-collateral', NULL);
