INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-04', '06:30:27', 37, 21, 1, 0, 0, 243, 59, 24.28, 'https://x.com/sandmark_news/status/2051187682210877878', '2/ COST BASIS RESISTANCE  Three key price bands now stack directly above spot, forming a "breakeven" wall:   🔹 Short-Term Holders (STH): $78,903  🔹 Spot ETF Buyers: $82,708   Any rally into this $3.8K zone is likely to encounter selling from participants eager to exit at cost. https://x.com/sandmark_news/status/2051187682210877878/photo/1', NULL);
INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-04', '06:30:28', 33, 19, 1, 0, 0, 165, 53, 32.12, 'https://x.com/sandmark_news/status/2051187685394629114', '3/ LONG-TERM HOLDER SUPPORT  Long-term holders (LTH) provide a structural counterweight. Their aggregate cost basis has risen from $28,749 in May 2025 to $47,929 today.  Spot currently trades ~58% above this level, a margin that historically signals sustained bull market conditions.', NULL);
INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-04', '07:13:11', 33, 20, 1, 0, 0, 187, 54, 28.88, 'https://x.com/sandmark_news/status/2051198437610467336', '2/ INFRASTRUCTURE GAINS  Accepting crypto is becoming "as easy as PayPal."   Major integrations with Visa, Mastercard, Stripe, and Shopify now support $USDC on Layer 2 networks like @base. This enables millions of merchants to tap into digital payment rails without the back-end complexity.', NULL);
INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-04', '07:13:12', 28, 18, 1, 0, 0, 150, 47, 31.33, 'https://x.com/sandmark_news/status/2051198440420593823', '3/ B2B DOMINANCE  The "real economy" stablecoin surge is driven by B2B settlements, which accounted for 60% ($226bn) of real-world payments in 2025—a massive 733% YoY increase.   While C2B (consumer) payments remain smaller, B2B is thriving thanks to faster clearing times and lower banking fees.', NULL);
