INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-06', '06:43:18', 32, 21, 1, 0, 0, 132, 54, 40.91, 'https://x.com/sandmark_news/status/2051915693931778525', '2/ Bridging the Gap: From Lockups to Liquidity  Securing #Ethereum via proof-of-stake typically requires 32 ETH and technical hardware.  @LidoFinance removes this friction by pooling deposits and routing them to professional operators, allowing users to earn rewards without the barriers of technical fluency or capital lockups.', NULL);
