INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-06', '23:12:37', 0, 0, 0, 0, 0, 0, 0, NULL, 'https://x.com/sandmark_news/status/2052164663660417293', 'CFTC data shows commercials (dealers/hedgers) have significantly reduced their short hedges, while large speculators and retail have deleveraged.   Options skew has flipped from heavy put dominance to modest call preference. This setup suggests spot buying - ETF flows, corporate treasuries, DeFi collateral rebuilding - is driving price action more than derivatives leverage.', NULL);
