INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-06', '23:12:38', 0, 0, 0, 0, 0, 0, 0, NULL, 'https://x.com/sandmark_news/status/2052164665166197224', 'The pattern break from previous dollar-weakness rallies highlights a more mature market regime.   With several macro catalysts ahead, Ethereum’s recovery appears built on cleaner positioning rather than speculative excess. $ETH', NULL);
INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-07', '06:11:34', 33, 22, 3, 0, 0, 191, 58, 30.37, 'https://x.com/sandmark_news/status/2052270094303252798', '2/ Looping Magnifies Hidden Exposures  Recursive "looping" stacks two exposures into one trade: the underlying yield and the borrowing cost. When pool utilization spikes, borrowing costs can exceed yield, inverting carry trades.  ➡️ This leaves loopers unable to unwind positions when liquidity dries up.', NULL);
INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-07', '06:11:35', 31, 18, 3, 0, 0, 164, 52, 31.71, 'https://x.com/sandmark_news/status/2052270098849915066', '4/ Market-Driven Capital Efficiency  Unlike governance-set protocols with hard-coded liquidation thresholds, @LotusFi_ allows the market to find its own inflection point. When a lender steps into a junior tranche to underwrite a higher threshold, it unlocks productive capital that was previously trapped.', NULL);
INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-07', '06:11:35', 35, 22, 2, 0, 0, 258, 59, 22.87, 'https://x.com/sandmark_news/status/2052270096568189241', '3/ Lotus Protocol Introduces Risk Segmentation  @LotusFi_ addresses these structural constraints by introducing credit tranches. Lenders choose the risk level they are willing to back, while borrowers select their collateral terms.  This segments risk into senior and junior tranches within a single market.', NULL);
