INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-07', '18:34:14', 31, 20, 3, 0, 0, 140, 54, 38.57, 'https://x.com/sandmark_news/status/2052456992795754705', 'Auyung emphasized the importance of guardrails: humans should make final buy/sell and custody decisions, while agents handle operations.   The company recently launched a $10mn fund for early-stage AI agent developers on its Minds platform and is in talks for a reverse merger with Current Group.', NULL);
INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-08', '02:42:42', 39, 17, 3, 0, 0, 172, 59, 34.3, 'https://x.com/sandmark_news/status/2052579920270827865', 'On addressing misconceptions:  “There’s a lot of misconceptions about me… so I’m here to spend more time, to engage with our community and trying to hopefully fix that." https://twitter.com/sandmark_news/status/2052579920270827865/photo/1', NULL);
INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-08', '02:42:42', 37, 22, 3, 0, 0, 155, 62, 40.0, 'https://x.com/sandmark_news/status/2052579917343203462', 'On past avoidance and renewed US engagement:  “For the last few years, I’ve been trying to avoid the US… Obviously, the US policy to crypto changed… and now I have to make up for this absence. I think there was a lack of engagement with US communities, lag of engagement with US builders, regulators, policy makers, etc."', NULL);
INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-08', '02:42:43', 37, 19, 3, 0, 0, 164, 59, 35.98, 'https://x.com/sandmark_news/status/2052579924142092393', 'On US leadership and the liquidity gap:  “The US has the fundamentals, the talent pool, the financial markets… traditional regulatory frameworks. The US right now is leading the world in terms of [crypto] policies... Now we are seeing the developers coming back. What is a little bit lagging in the US right now is the liquidity, so the best liquidity in crypto is outside the US… Binance has the best liquidity in this market and we’d love to be able to provide that in some way, either revitalizing Binance or somehow providing the US the best liquidity in the world."', NULL);
INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-08', '02:42:44', 38, 18, 3, 0, 0, 200, 59, 29.5, 'https://x.com/sandmark_news/status/2052579927761776672', 'On the three fundamental technologies:  “I think in my adult life, there''s really three fundamental technologies. There''s Internet, there''s blockchain, there''s AI. All three technologies are borderless. They''re global."  “All the blockchains need to be AI ready." https://twitter.com/sandmark_news/status/2052579927761776672/photo/1', NULL);
