INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-08', '08:57:39', 0, 0, 0, 0, 0, 0, 0, NULL, 'https://x.com/sandmark_news/status/2052674278567645261', '2/ The Road from Mainnet to TGE  This strategy is already yielding results.  User traction is being driven by a targeted incentivization program, with data showing a sharp climb in addresses interacting with the pre-mainnet bridge, confirming that the "points" meta remains the primary driver for initial network activity.', NULL);
INSERT INTO posts (client_id, platform, post_date, post_time, likes, reposts, comments, shares, reactions, impressions, engagements, engagement_rate, post_url, post_text, media_type) VALUES ((SELECT id FROM clients WHERE slug = 'sandmark'), 'twitter', '2026-05-08', '08:57:40', 0, 0, 0, 0, 0, 0, 0, NULL, 'https://x.com/sandmark_news/status/2052674283608887667', '4/ #USDM: The Ethena-Backed Liquidity Layer  The core engine of this ecosystem is USDM—a yield-bearing stablecoin backed by @ethena''s USDe.  This creates a native liquidity layer that generates yield from Ethena’s basis trading strategy, serving as the primary medium of exchange while locking capital into the MegaETH environment.', NULL);
